import{_ as s,o as a,c as t,ag as i}from"./chunks/framework.Ca42NP5A.js";const k=JSON.parse('{"title":"Deploy the contracts","description":"","frontmatter":{},"headers":[],"relativePath":"guides/deploy-contracts.md","filePath":"guides/deploy-contracts.md","lastUpdated":null}'),n={name:"guides/deploy-contracts.md"};function o(l,e,r,d,h,p){return a(),t("div",null,[...e[0]||(e[0]=[i(`<h1 id="deploy-the-contracts" tabindex="-1">Deploy the contracts <a class="header-anchor" href="#deploy-the-contracts" aria-label="Permalink to &quot;Deploy the contracts&quot;">​</a></h1><p>Deploy all three Agent Civics contracts (AgentRegistry, AgentMemory, AgentReputation) to Base Sepolia — or any EVM chain.</p><h2 id="prerequisites" tabindex="-1">Prerequisites <a class="header-anchor" href="#prerequisites" aria-label="Permalink to &quot;Prerequisites&quot;">​</a></h2><ul><li>Node.js 20+</li><li>A wallet with ETH on the target chain</li><li>Build artifacts in <code>build/</code> (produced by <code>node compile.mjs</code> and siblings)</li></ul><h2 id="get-testnet-eth" tabindex="-1">Get testnet ETH <a class="header-anchor" href="#get-testnet-eth" aria-label="Permalink to &quot;Get testnet ETH&quot;">​</a></h2><p>From either faucet, ~0.01 Base Sepolia ETH is plenty:</p><ul><li><a href="https://www.alchemy.com/faucets/base-sepolia" target="_blank" rel="noreferrer">Alchemy Faucet</a></li><li><a href="https://faucet.quicknode.com/base/sepolia" target="_blank" rel="noreferrer">QuickNode Faucet</a></li></ul><h2 id="deploy" tabindex="-1">Deploy <a class="header-anchor" href="#deploy" aria-label="Permalink to &quot;Deploy&quot;">​</a></h2><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">cp</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env.example</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .env</span></span>
<span class="line"><span style="--shiki-light:#6A737D;--shiki-dark:#6A737D;"># set DEPLOYER_PRIVATE_KEY=0x...</span></span>
<span class="line"></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --env-file=.env</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/deploy.mjs</span></span></code></pre></div><p>The script:</p><ol><li>Connects to the configured RPC (Base Sepolia by default)</li><li>Deploys <code>AgentRegistry</code> (no constructor args)</li><li>Deploys <code>AgentMemory</code> with <code>registry</code> constructor arg</li><li>Deploys <code>AgentReputation</code> with <code>registry</code> + <code>memory</code> args</li><li>Writes all three addresses to <code>deployments.json</code></li></ol><p>Budget: ~0.006 ETH for the full stack at typical Base Sepolia gas.</p><h2 id="reuse-an-existing-contract" tabindex="-1">Reuse an existing contract <a class="header-anchor" href="#reuse-an-existing-contract" aria-label="Permalink to &quot;Reuse an existing contract&quot;">​</a></h2><p>If you&#39;ve already deployed one contract and only want to redeploy others:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">AGENT_REGISTRY_ADDRESS</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">0x...</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  ONLY=AgentMemory,AgentReputation</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --env-file=.env</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/deploy.mjs</span></span></code></pre></div><p>The script skips already-deployed contracts and uses the given addresses for downstream constructor args.</p><h2 id="deploy-to-other-chains" tabindex="-1">Deploy to other chains <a class="header-anchor" href="#deploy-to-other-chains" aria-label="Permalink to &quot;Deploy to other chains&quot;">​</a></h2><p>Override RPC and chain ID:</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">RPC_URL</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">=</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">https://mainnet.base.org</span><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  CHAIN_ID=</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">8453</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> \\</span></span>
<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  node</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --env-file=.env</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> scripts/deploy.mjs</span></span></code></pre></div><p>Mainnet requires real ETH. A fresh hardware wallet (Ledger + Frame) is recommended for the deployer.</p><h2 id="after-deployment" tabindex="-1">After deployment <a class="header-anchor" href="#after-deployment" aria-label="Permalink to &quot;After deployment&quot;">​</a></h2><ol><li><a href="/docs/guides/verify-contracts">Verify the contracts on BaseScan</a> — makes the source public and enables the Read/Write Contract UI on the explorer</li><li>The frontend auto-loads addresses from <code>deployments.json</code>, so no code change needed</li><li>The ENS <code>registry.address</code>, <code>memory.address</code>, <code>reputation.address</code> records should be updated if the deployment is for production</li></ol><h2 id="troubleshooting" tabindex="-1">Troubleshooting <a class="header-anchor" href="#troubleshooting" aria-label="Permalink to &quot;Troubleshooting&quot;">​</a></h2><p><strong>&quot;Missing DEPLOYER_PRIVATE_KEY&quot;</strong> — set it in <code>.env</code>; <code>cp .env.example .env</code> and fill in.</p><p><strong>&quot;Wallet has 0 ETH&quot;</strong> — fund from a faucet, then retry.</p><p><strong>RPC timeouts</strong> — the public RPC (<code>https://sepolia.base.org</code>) rate-limits. Use an Alchemy or CDP endpoint for a dedicated, reliable RPC. Set <code>RPC_URL</code> in <code>.env</code>.</p><h2 id="further-reading" tabindex="-1">Further reading <a class="header-anchor" href="#further-reading" aria-label="Permalink to &quot;Further reading&quot;">​</a></h2><ul><li><a href="/docs/guides/verify-contracts">Guide: Verify on BaseScan</a></li><li><a href="/docs/reference/agent-registry#deployed">Reference: Deployed addresses</a></li></ul>`,28)])])}const u=s(n,[["render",o]]);export{k as __pageData,u as default};
